const crypto = require('crypto');
const secret = $env.LINE_CHANNEL_SECRET_HOLM_AGENTS;
if (!secret) throw new Error('LINE_CHANNEL_SECRET_HOLM_AGENTS not set (n8n env)');
const item = $input.first();
let raw;
try {
  raw = await this.helpers.getBinaryDataBuffer(0, 'data');
} catch (e) {
  raw = Buffer.from(JSON.stringify(item.json.body || {}));
}
const sig = (item.json.headers || {})['x-line-signature'];
const expected = crypto.createHmac('sha256', secret).update(raw).digest('base64');
if (expected !== sig) return [{ json: { valid: false } }];
const body = JSON.parse(raw.toString());
return [{ json: { valid: true, events: body.events || [] } }];

// Normalized Message Schema (PLAN-002 T2.2 / Spec section 2)
const events = $('Verify Signature').first().json.events || [];
const out = [];
for (const e of events) {
  const ok = (e.type === 'message' && e.message && e.message.type === 'text') || e.type === 'follow' || e.type === 'postback';
  if (!ok) continue; // sticker/image/voice -> fallback message ตาม catalog (ทำใน T2.5)
  const rand = Math.random().toString(36).slice(2, 8);
  out.push({ json: {
    job_id: 'jv_' + Date.now() + '_' + rand,
    channel: 'line',
    channel_user_id: e.source ? e.source.userId : null,
    type: e.type === 'postback' ? 'button_callback' : (e.type === 'follow' ? 'follow' : 'message'),
    text: e.message ? e.message.text : '',
    callback_data: e.postback ? e.postback.data : null,
    event_id: e.webhookEventId,
    reply_ref: { line_reply_token: e.replyToken || null },
    ts: e.timestamp ? new Date(e.timestamp).toISOString() : new Date().toISOString()
  }});
}
return out;

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  if (j.inserted !== true || !j.msg) continue;
  out.push({ json: typeof j.msg === 'string' ? JSON.parse(j.msg) : j.msg });
}
return out;

const rows = $input.all();
const out = [];
for (let i = 0; i < rows.length; i++) {
  const msg = $('Filter New Events').itemMatching(i).json;
  const id = rows[i].json || {};
  out.push({ json: { ...msg, identity_id: id.identity_id || null, identity_status: id.status || null, role: id.role || null } });
}
return out;

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const token = j.reply_ref && j.reply_ref.line_reply_token;
  if (!token) continue;
  const text = j.identity_status === 'approved'
    ? 'สวัสดีครับ ผม Javis 🤖 ผู้ช่วยคลังความรู้ของทีม พิมพ์คำถามได้เลยครับ'
    : 'สวัสดีครับ ผม Javis 🤖 ผู้ช่วยคลังความรู้ของทีม\nพิมพ์ข้อความอะไรก็ได้เพื่อเริ่มลงทะเบียนครับ';
  out.push({ json: { kind: 'reply', body: JSON.stringify({ replyToken: token, messages: [{ type: 'text', text }] }) } });
}
return out;

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const text = 'คำขอของคุณกำลังรอ Admin อนุมัติครับ 🙏 เดี๋ยวผมแจ้งทันทีที่ใช้งานได้';
  if (j.channel === 'telegram' && j.reply_ref && j.reply_ref.telegram_chat_id) {
