  } else if (j.reply_ref && j.reply_ref.line_reply_token) {
    out.push({ json: { kind: 'reply', body: JSON.stringify({ replyToken: j.reply_ref.line_reply_token, messages: [{ type: 'text', text }] }) } });
  }
}
return out;

const out = [];
const rows = $input.all();
for (let i = 0; i < rows.length; i++) {
  const src = $('Route').itemMatching(i).json;
  const r = rows[i].json || {};
  const textUser = r.new_identity_id ? 'ส่งคำขอลงทะเบียนให้ Admin แล้วครับ 🙏 รออนุมัติสักครู่' : 'คำขอของคุณกำลังรอ Admin อนุมัติครับ 🙏';
  if (src.channel === 'telegram' && src.reply_ref && src.reply_ref.telegram_chat_id) {
    out.push({ json: { channel: 'telegram', tg_method: 'sendMessage', body: JSON.stringify({ chat_id: src.reply_ref.telegram_chat_id, text: textUser }) } });
  } else if (src.reply_ref && src.reply_ref.line_reply_token) {
    out.push({ json: { kind: 'reply', body: JSON.stringify({ replyToken: src.reply_ref.line_reply_token, messages: [{ type: 'text', text: textUser }] }) } });
  }
  if (r.new_identity_id && r.admin_uid) {
    const chanLabel = src.channel === 'telegram' ? 'Telegram' : 'LINE';
    out.push({ json: { kind: 'push', body: JSON.stringify({ to: r.admin_uid, messages: [{ type: 'template', altText: 'คำขอลงทะเบียนใหม่', template: { type: 'buttons', title: '📥 คำขอลงทะเบียนใหม่', text: chanLabel + ' user: ' + String(src.channel_user_id).slice(0, 12) + '…', actions: [{ type: 'postback', label: 'อนุมัติ VIEWER', data: 'action=approve_reg&cid=' + r.new_identity_id + '&role=VIEWER' }, { type: 'postback', label: 'อนุมัติ CONTRIBUTOR', data: 'action=approve_reg&cid=' + r.new_identity_id + '&role=CONTRIBUTOR' }, { type: 'postback', label: 'ปฏิเสธ', data: 'action=reject_reg&cid=' + r.new_identity_id }] } }] }) } });
  }
}
return out;

function parseQS(s) {
  const p = {};
  for (const kv of String(s || '').split('&')) {
    const i = kv.indexOf('=');
    if (i > 0) p[kv.slice(0, i)] = decodeURIComponent(kv.slice(i + 1));
  }
  return p;
}
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const params = parseQS(j.callback_data);
  const action = params.action;
  const cid = params.cid;
  if (!cid || !['approve_reg', 'reject_reg'].includes(action)) continue;
  let role = params.role || 'VIEWER';
  if (!['VIEWER', 'CONTRIBUTOR'].includes(role)) role = 'VIEWER';
  out.push({ json: { cid, new_status: action === 'approve_reg' ? 'approved' : 'rejected', role, admin_reply_token: j.reply_ref && j.reply_ref.line_reply_token } });
}
return out;

const out = [];
const rows = $input.all();
for (let i = 0; i < rows.length; i++) {
  const src = $('Parse Approval').itemMatching(i).json;
  const r = rows[i].json || {};
  if (src.admin_reply_token) {
    const text = !r.target_uid ? 'รายการนี้ถูกดำเนินการไปแล้วครับ' : (r.new_status === 'approved' ? '✅ อนุมัติแล้ว — สิทธิ์ ' + (r.granted_role || 'VIEWER') : '🚫 ปฏิเสธแล้ว');
    out.push({ json: { kind: 'reply', body: JSON.stringify({ replyToken: src.admin_reply_token, messages: [{ type: 'text', text }] }) } });
  }
  if (r.target_uid) {
    const text = r.new_status === 'approved' ? 'ลงทะเบียนสำเร็จ 🎉 สิทธิ์ของคุณ: ' + (r.granted_role || 'VIEWER') + '\nพิมพ์คำถามได้เลยครับ' : 'ขออภัยครับ คำขอลงทะเบียนไม่ได้รับอนุมัติ สอบถามเพิ่มเติมได้ที่ Admin ครับ';
    if (r.target_chan === 'telegram') {
      out.push({ json: { channel: 'telegram', tg_method: 'sendMessage', body: JSON.stringify({ chat_id: r.target_uid, text }) } });
    } else {
      out.push({ json: { kind: 'push', body: JSON.stringify({ to: r.target_uid, messages: [{ type: 'text', text }] }) } });
    }
  }
}
return out;

const tree = $input.first().json.tree || [];
const keep = /^(README\.md|CONTRIBUTING\.md|prompts\/qa-system\.md|domains\/.+\.md|guides\/.+\.md|plans\/.+\.md|glossary\/.+\.md)$/;
const files = tree.filter(t => t.type === 'blob' && keep.test(t.path)).sort((a, b) => a.path.localeCompare(b.path));
if (files.length === 0) throw new Error('no KB files matched');
return files.map(f => ({ json: { path: f.path, url: f.url } }));

const paths = $('QA Pick Files').all().map(i => i.json.path);
const blobs = $input.all();
if (paths.length !== blobs.length) throw new Error('path/blob count mismatch');
const src = $('Join Identity').first().json;
const question = src.text;
if (!question) throw new Error('no question text');
const histRow = $('Session Read').first().json || {};
let history = [];
try { history = typeof histRow.history === 'string' ? JSON.parse(histRow.history) : (histRow.history || []); } catch (e) { history = []; }

let systemPrompt = 'คุณคือ Javis ผู้ช่วยคลังความรู้ของทีม ตอบจากเอกสารเท่านั้น ใช้ citations เสมอ';
const documents = [];
for (let i = 0; i < paths.length; i++) {
  const raw = blobs[i].json.content || '';
  const text = Buffer.from(raw.replace(/\n/g, ''), 'base64').toString('utf8');
  if (paths[i] === 'prompts/qa-system.md') {
    const m = text.match(/```([\s\S]*?)```/);
    if (m) systemPrompt = m[1].trim();
    continue;
  }
  documents.push({ type: 'document', source: { type: 'text', media_type: 'text/plain', data: text }, title: paths[i], citations: { enabled: true } });
}
documents[documents.length - 1].cache_control = { type: 'ephemeral' };

const msgs = [
  { role: 'user', content: documents },
  { role: 'assistant', content: 'รับทราบครับ ผมจะตอบจากเอกสารเหล่านี้เท่านั้น' }
];
for (const h of history) {
  if (h && (h.role === 'user' || h.role === 'assistant') && h.content) {
    msgs.push({ role: h.role, content: String(h.content).slice(0, 2000) });
  }
}
msgs.push({ role: 'user', content: 'ใช้ citations ประกอบทุกข้อเท็จจริงเสมอ\n\nคำถาม: ' + question });

const body = {
  model: 'claude-sonnet-5',
  max_tokens: 2048,
  output_config: { effort: 'low' },
  system: [{ type: 'text', text: systemPrompt }],
  messages: msgs
};
return [{ json: { body: JSON.stringify(body), reply_token: src.reply_ref && src.reply_ref.line_reply_token, job_id: src.job_id, question, channel_user_id: src.channel_user_id, channel: src.channel, tg_chat_id: src.reply_ref && src.reply_ref.telegram_chat_id } }];

const resp = $input.first().json;
let answer = '';
const cited = new Set();
for (const b of resp.content || []) {
  if (b.type === 'text') {
    answer += b.text;
    for (const c of b.citations || []) cited.add(c.document_title);
  }
}
if (!answer) answer = 'ขออภัยครับ ระบบขัดข้องชั่วคราว ลองใหม่อีกครั้งครับ 🙏';
if (answer.length > 3900) answer = answer.slice(0, 3900) + '…';
const citeText = cited.size ? '\n\n📎 อ้างอิง: ' + [...cited].join(', ') : '';
const req = $('QA Build Request').first().json;
if (req.channel === 'telegram' && req.tg_chat_id) {
  return [{ json: { channel: 'telegram', tg_method: 'sendMessage', body: JSON.stringify({ chat_id: req.tg_chat_id, text: answer + citeText, reply_markup: { inline_keyboard: [[{ text: '👍 ตอบตรง', callback_data: 'action=fb&r=up&job=' + req.job_id }, { text: '👎 ยังไม่ใช่', callback_data: 'action=fb&r=down&job=' + req.job_id }]] } }) } }];
}
return [{ json: { kind: 'reply', body: JSON.stringify({ replyToken: req.reply_token, messages: [{ type: 'text', text: answer + citeText, quickReply: { items: [{ type: 'action', action: { type: 'postback', label: '👍 ตอบตรง', data: 'action=fb&r=up&job=' + req.job_id } }, { type: 'action', action: { type: 'postback', label: '👎 ยังไม่ใช่', data: 'action=fb&r=down&job=' + req.job_id } }] } }] }) } }];

const src = $('Join Identity').first().json;
const lim = $input.first().json.lim;
const text = 'ชั่วโมงนี้คุณถามครบโควต้าแล้วครับ (' + lim + ' คำถาม/ชม.) ถามได้อีกครั้งต้นชั่วโมงหน้า 🙏';
if (src.channel === 'telegram' && src.reply_ref && src.reply_ref.telegram_chat_id) {
  return [{ json: { channel: 'telegram', tg_method: 'sendMessage', body: JSON.stringify({ chat_id: src.reply_ref.telegram_chat_id, text }) } }];
}
const token = src.reply_ref && src.reply_ref.line_reply_token;
if (!token) return [];
return [{ json: { kind: 'reply', body: JSON.stringify({ replyToken: token, messages: [{ type: 'text', text }] }) } }];

const resp = $input.first().json;
let answer = '';
const cited = [];
for (const b of resp.content || []) {
  if (b.type === 'text') {
    answer += b.text;
    for (const c of b.citations || []) if (!cited.includes(c.document_title)) cited.push(c.document_title);
  }
}
const req = $('QA Build Request').first().json;
const u = resp.usage || {};
const cost = ((u.input_tokens || 0) * 3 + (u.cache_creation_input_tokens || 0) * 3.75 + (u.cache_read_input_tokens || 0) * 0.3 + (u.output_tokens || 0) * 15) / 1e6;
return [{ json: {
  channel_user_id: req.channel_user_id,
  channel: req.channel,
  question: String(req.question).slice(0, 3000),
  answer: answer.slice(0, 3000),
  job_id: req.job_id,
  cost_usd: Math.round(cost * 10000) / 10000,
  detail: JSON.stringify({ question: String(req.question).slice(0, 1000), answer: answer.slice(0, 1500), citations: cited })
} }];

function parseQS(s) {
  const p = {};
  for (const kv of String(s || '').split('&')) {
    const i = kv.indexOf('=');
    if (i > 0) p[kv.slice(0, i)] = decodeURIComponent(kv.slice(i + 1));
  }
  return p;
}
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const params = parseQS(j.callback_data);
  if (params.action !== 'fb') continue;
  out.push({ json: { job_id: params.job || '', rating: params.r === 'up' ? 'up' : 'down', uid: j.channel_user_id, channel: j.channel, cb_id: j.reply_ref && j.reply_ref.callback_query_id, reply_token: j.reply_ref && j.reply_ref.line_reply_token } });
}
return out;

const out = [];
const rows = $input.all();
for (let i = 0; i < rows.length; i++) {
  const src = $('Parse Feedback').itemMatching(i).json;
  const text = rows[i].json.rating === 'down' ? 'รับทราบครับ ทีมจะปรับปรุง 🙏' : 'ขอบคุณครับ 🙏';
  if (src.channel === 'telegram' && src.cb_id) {
    out.push({ json: { channel: 'telegram', tg_method: 'answerCallbackQuery', body: JSON.stringify({ callback_query_id: src.cb_id, text }) } });
  } else if (src.reply_token) {
    out.push({ json: { kind: 'reply', body: JSON.stringify({ replyToken: src.reply_token, messages: [{ type: 'text', text }] }) } });
  }
}
return out;

const crypto = require('crypto');
const expect = crypto.createHash('sha256').update($env.TELEGRAM_BOT_TOKEN_JAVIS || '').digest('hex');
const out = [];
for (const item of $input.all()) {
  const h = (item.json.headers || {})['x-telegram-bot-api-secret-token'];
  if (h === expect && item.json.body) out.push({ json: item.json.body });
}
return out;

const out = [];
for (const item of $input.all()) {
  const u = item.json;
  if (!u || typeof u.update_id === 'undefined') continue;
  let type = null, text = '', cud = null, chatId = null, cbId = null, cbData = '';
  if (u.message && u.message.from && u.message.text) {
    type = 'message'; text = u.message.text; cud = String(u.message.from.id); chatId = u.message.chat && u.message.chat.id;
  } else if (u.callback_query && u.callback_query.from) {
    type = 'button_callback'; cbData = u.callback_query.data || ''; cud = String(u.callback_query.from.id);
    chatId = u.callback_query.message && u.callback_query.message.chat && u.callback_query.message.chat.id;
    cbId = u.callback_query.id;
  } else { continue; }
  const job_id = 'jv_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
  out.push({ json: { job_id, channel: 'telegram', channel_user_id: cud, type, text, callback_data: cbData, event_id: 'tg_' + u.update_id, reply_ref: { telegram_chat_id: chatId, callback_query_id: cbId }, ts: new Date().toISOString() } });
}
return out;

const src = $('Join Identity').first().json;
let intent = 'qa';
try {
  const resp = $input.first().json || {};
  const t = (resp.content || []).map(b => b.text || '').join('');
  const m = t.match(/\{[\s\S]*\}/);
  if (m) intent = (JSON.parse(m[0]).intent || 'qa');
} catch (e) { intent = 'qa'; }
if (!['qa', 'help', 'smalltalk'].includes(intent)) intent = 'qa';
return [{ json: { ...src, intent } }];

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const text = j.intent === 'help'
    ? 'ผม Javis ผู้ช่วยคลังความรู้ของทีมครับ 🤖\nถามได้เลย เช่น\n• "Javis มีฟีเจอร์อะไรบ้าง"\n• "branch strategy ของเราเป็นยังไง"\n• "taskbot เก็บข้อมูลอะไรบ้าง"\nผมตอบพร้อมอ้างอิงเอกสารเสมอ และจำบทสนทนาต่อเนื่อง ~30 นาทีครับ'
    : 'ยินดีครับ 🙌 มีอะไรอยากรู้จากคลังความรู้ของทีม ถามได้เลยครับ';
  if (j.channel === 'telegram' && j.reply_ref && j.reply_ref.telegram_chat_id) {
    out.push({ json: { channel: 'telegram', tg_method: 'sendMessage', body: JSON.stringify({ chat_id: j.reply_ref.telegram_chat_id, text }) } });
  } else if (j.reply_ref && j.reply_ref.line_reply_token) {
    out.push({ json: { kind: 'reply', body: JSON.stringify({ replyToken: j.reply_ref.line_reply_token, messages: [{ type: 'text', text }] }) } });
  }
}
return out;
